#!/bin/bash
set -euo pipefail
cd /root/ARCARNA

mkdir -p "$(dirname 'client/src/pages/settings/developer.tsx')"
python3 - <<'PYEOF'
import base64, pathlib
p = pathlib.Path('client/src/pages/settings/developer.tsx')
p.write_bytes(base64.b64decode(''))
print('Wrote', p, 'bytes=', p.stat().st_size)
PYEOF

npm run build
pm2 restart ARCARNA
echo 'Done — hard refresh (Cmd+Shift+R) the Developer page'
